B.a4U=s(["\u0110\u1ee1 n\u1ed5i {skill} c\u1ee7a ta kh\xf4ng?","T\u1edbi l\xfac ta tung {skill} r\u1ed3i.","{skill} n\xe0y s\u1ebd kh\xf3a \u0111\u01b0\u1eddng lui c\u1ee7a ng\u01b0\u01a1i.","Ta s\u1ebd ph\u1ea3i tung {skill} n\xe0y.","{skill} b\u1eafn tung l*n ng\u01b0\u01a1i.","{skill} .","Ta s\u1ebd tung k\u1ef9 n\u0103ng gia truy\u1ec1n: {skill}","\xdam ba la s\xec l\xe0 b\xf9a {skill}","Chu\u1ea9n b\u1ecb \u0103n {skill} \u0111i!","\u0110\u1eebng ch\u1edbp m\u1eaft, {skill} t\u1edbi r\u1ed3i.","{skill} incoming!","N\xe9 \u0111\u01b0\u1ee3c th\xec n\xe9 {skill} n\xe0y \u0111i.","{skill} n\xe0y tao gi\u1eef t\u1eeb \u0111\u1ea7u tr\u1eadn \u0111\xf3.","\u0110\xe2y l\xe0 l\xfac {skill} l\xean ti\u1ebfng.","{skill} kh\xf4ng ph\u1ea3i \u0111\u1ec3 ch\u01a1i \u0111\xe2u.","M\u1ed9t chi\xeau {skill}, m\u1ed9t m\u1ea1ng.","\u0102n tr\u1ecdn {skill} n\xe0y nh\xe9.","{skill} s\u1ebd k\u1ebft th\xfac ng\u01b0\u01a1i.","Charge xong r\u1ed3i, x\u1ea3 {skill}!","{skill} full power!","\u0110\xe2y l\xe0 {skill} m\u1ea1nh nh\u1ea5t c\u1ee7a ta.","\u0110\u1ee1 th\u1eed {skill} max damage coi.","{skill} n\xe0y crit ch\u1eafc lu\xf4n.","\u0110\u1ee9ng y\xean \u0111\xf3, \u0103n {skill} cho g\u1ecdn.","Ch\u1ea1y \u0111i, c\xf2n k\u1ecbp n\xe9 {skill}.","{skill} n\xe0y kh\xf4ng tr\u01b0\u1ee3t \u0111\xe2u.","Ng\u01b0\u01a1i kh\xf4ng tho\xe1t kh\u1ecfi {skill} \u0111\xe2u.","{skill} kh\xf3a lu\xf4n \u0111\u01b0\u1eddng ch\u1ea1y.","Tao b\u1eaft \u0111\u1ea7u nghi\xeam t\xfac r\u1ed3i: {skill}","\u0110\xe2y m\u1edbi l\xe0 s\u1ee9c m\u1ea1nh th\u1eadt: {skill}","{skill} n\xe0y tao kh\xf4ng d\xf9ng b\u1eeba \u0111\xe2u.","T\u1edbi c\xf4ng chuy\u1ec7n v\u1edbi {skill} r\u1ed3i \u0111\xf3.","{skill} s\u1ebd d\u1ea1y ng\u01b0\u01a1i b\xe0i h\u1ecdc.","H\xedt s\xe2u \u0111i, s\u1eafp \u0103n {skill}.","{skill} t\u1edbi n\u01a1i r\u1ed3i, chu\u1ea9n b\u1ecb ch\u01b0a?","M\u1ed9t gi\xe2y n\u1eefa th\xf4i, {skill} s\u1ebd n\u1ed5.","\u0110\u1ebfm ng\u01b0\u1ee3c\u2026 3\u20262\u20261\u2026 {skill}!","{skill} b\xf9ng n\u1ed5!","\xc1i ch\xe0, test nh\u1eb9 {skill} c\xe1i coi.","{skill} n\xe0y xem m\xe0y ch\u1ecbu n\u1ed5i kh\xf4ng.","Th\u1eed {skill} xem ph\u1ea3n \u1ee9ng sao.","{skill} n\xe0y d\xe0nh ri\xeang cho m\xe0y \u0111\xf3.","\u0110\u1eebng c\xf3 kh\xf3c khi \u0103n {skill}.","{skill} ra tay!","{skill} k\xedch ho\u1ea1t!","Thi tri\u1ec3n {skill}!","B\u1eaft \u0111\u1ea7u {skill}!","{skill} unleashed!","\u0110\xe2y l\xe0 chi\xeau ta gi\u1ea5u n\xe3y gi\u1edd: {skill}","Ng\u01b0\u01a1i \xe9p ta ph\u1ea3i d\xf9ng {skill}.","{skill} \u2013 \u0111\xf2n k\u1ebft li\u1ec5u!","{skill} \u2013 kh\xf4ng \u0111\u01b0\u1eddng lui!","{skill} \u2013 ch\u1ea5m h\u1ebft!","Tao m\xe0 \u0111\xe3 x\xe0i {skill} l\xe0 c\xf3 ng\u01b0\u1eddi n\u1eb1m.","{skill} n\xe0y kh\xf4ng \u0111\xf9a \u0111\u01b0\u1ee3c \u0111\xe2u.","\u0102n {skill} xong nh\u1edb \u0111\u1ee9ng d\u1eady nha\u2026 \xe0 m\xe0 th\xf4i.","{skill} n\xe0y h\u01a1i \u0111au \u0111\xf3, r\xe1ng ch\u1ecbu.","{skill} \u2013 d\xe0nh cho k\u1ebb xui x\u1ebbo.","\xdam ba la\u2026 {skill} xu\u1ea5t hi\u1ec7n!","{skill} t\u1eeb tr\xean tr\u1eddi r\u01a1i xu\u1ed1ng!","Tri\u1ec7u h\u1ed3i {skill}!","{skill} gi\xe1ng xu\u1ed1ng!","{skill} ph\u1ee7 \u0111\u1ea7u!","\u0110\u1ee7 r\u1ed3i, k\u1ebft th\xfac b\u1eb1ng {skill}.","{skill} s\u1ebd kh\xe9p l\u1ea1i tr\u1eadn n\xe0y.","H\u1ea1 m\xe0n v\u1edbi {skill}.","\u0110\xf2n cu\u1ed1i: {skill}.","{skill} \u2013 goodbye!"],t.s)
